import json
import re

# Load English Literature & Fiction books
english_books = var_functions.query_db_50

# Load review data
reviews = var_functions.query_db_52

print(f"English Literature & Fiction books: {len(english_books)}")
print(f"Reviews: {len(reviews)}")

# Extract book numbers and create mapping
book_map = {}
for book in english_books:
    match = re.search(r'bookid_(\d+)', book['book_id'])
    if match:
        book_num = int(match.group(1))
        book_map[book_num] = {
            'book_id': book['book_id'],
            'title': book['title'],
            'details': book['details'],
            'categories': book['categories']
        }

# Group reviews by book number
reviews_by_book = {}
for review in reviews:
    match = re.search(r'purchaseid_(\d+)', review['purchase_id'])
    if match:
        book_num = int(match.group(1))
        if book_num not in reviews_by_book:
            reviews_by_book[book_num] = []
        reviews_by_book[book_num].append(float(review['rating']))

print(f"Books with reviews: {len(reviews_by_book)}")

# Calculate average ratings for Literature & Fiction books
perfect_books = []
for book_num, book_info in book_map.items():
    if book_num in reviews_by_book:
        ratings = reviews_by_book[book_num]
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating == 5.0 and len(ratings) > 0:
            perfect_books.append({
                'title': book_info['title'],
                'book_id': book_info['book_id'],
                'rating_count': len(ratings),
                'avg_rating': avg_rating
            })

print(f"Books with perfect 5.0 average rating: {len(perfect_books)}")

# Return result
result = json.dumps(perfect_books, indent=2)
print("__RESULT__:")
